import 'package:bookly/Core/Utils/Widget/custom_loading.dart';import 'package:flutter/material.dart';import 'package:flutter_bloc/flutter_bloc.dart';import '../../../../ViewBooks/View/view_book.dart';import '../../../ViewModel/FeatureCubit/featured_cubit.dart';class ProductBuilder extends StatelessWidget {  final double? aspectRatio;  const ProductBuilder({super.key, this.aspectRatio});  @override  Widget build(BuildContext context) {    return BlocConsumer<FeaturedCubit, FeaturedState>(      listener: (context, state) {        // TODO: implement listener      },      builder: (context, state) {        if (state is FeaturedSuccess) {          return Padding(            padding: const EdgeInsets.only(left: 35, top: 20, bottom: 40),            child: SizedBox(              height: aspectRatio ?? MediaQuery.of(context).size.height * .27,              child: ListView.separated(                  scrollDirection: Axis.horizontal,                  itemBuilder: (context, index) {                    return InkWell(                        onTap: () => Navigator.push(                            context,                            MaterialPageRoute(                              builder: (context) => const ViewInformationBook(),                            )),                        child: AspectRatio(                            aspectRatio: 2.5 / 4,                            child: Container(                              decoration: BoxDecoration(                                  image: DecorationImage(                                    image: NetworkImage(state.books[index]                                        .volumeInfo!.imageLinks!.thumbnail!),                                    fit: BoxFit.fill,                                    filterQuality: FilterQuality.high,                                  ),                                  borderRadius: const BorderRadius.all(                                      Radius.circular(20))),                            )));                  },                  separatorBuilder: (context, index) => const SizedBox(                        width: 20,                      ),                  itemCount: 10),            ),          );        } else if (state is FeaturedFailure) {          return Text(state.error);        } else {          return const CustomLoading();        }      },    );  }}